const input = $input.item.json || {};

const rawQuery = input.query ?? input.q ?? input.searchQuery;
if (typeof rawQuery !== 'string' || !rawQuery.trim()) {
  throw new Error('Missing required input field: query');
}

const parseInteger = (value, fallback) => {
  const parsed = parseInt(value, 10);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const normalizeString = (value, fallback) => {
  if (typeof value !== 'string') return fallback;
  const trimmed = value.trim();
  return trimmed || fallback;
};

const safesearchAllowed = new Set(['off', 'moderate', 'strict']);
const freshnessAllowed = new Set(['', 'pd', 'pw', 'pm', 'py']);

const count = clamp(parseInteger(input.count ?? input.limit, 10), 1, 20);
const readTopN = clamp(parseInteger(input.readTopN ?? input.read_top_n ?? input.readerLimit, 3), 0, 5);
const readerDelaySeconds = clamp(parseInteger(input.readerDelaySeconds ?? input.reader_delay_seconds, 4), 1, 60);
const maxContentChars = clamp(parseInteger(input.maxContentChars ?? input.max_content_chars, 6000), 1000, 50000);

const safesearchInput = normalizeString(input.safesearch, 'moderate');
const freshnessInput = normalizeString(input.freshness, '');

return {
  json: {
    query: rawQuery.trim(),
    count,
    readTopN,
    readerDelaySeconds,
    maxContentChars,
    country: normalizeString(input.country, 'US').toUpperCase(),
    search_lang: normalizeString(input.search_lang ?? input.searchLang, 'en'),
    ui_lang: normalizeString(input.ui_lang ?? input.uiLang, 'en-US'),
    safesearch: safesearchAllowed.has(safesearchInput) ? safesearchInput : 'moderate',
    freshness: freshnessAllowed.has(freshnessInput) || /^\d{4}-\d{2}-\d{2}to\d{4}-\d{2}-\d{2}$/.test(freshnessInput)
      ? freshnessInput
      : '',
    requestedAt: new Date().toISOString()
  }
};

const brave = $input.item.json || {};
const request = $('Normalize Input').first().json;
const webResults = Array.isArray(brave.web?.results) ? brave.web.results : [];

const normalizeUrlKey = (url) => String(url || '').trim().replace(/\/$/, '');
const seenUrls = new Set();
const candidates = [];

for (const result of webResults) {
  const url = String(result.url || '').trim();
  if (!url) continue;

  const key = normalizeUrlKey(url);
  if (seenUrls.has(key)) continue;
  seenUrls.add(key);

  candidates.push({
    rank: candidates.length + 1,
    title: result.title || '',
    url,
    description: result.description || '',
    age: result.age || null,
    pageAge: result.page_age || null,
    language: result.language || null,
    familyFriendly: typeof result.family_friendly === 'boolean' ? result.family_friendly : null,
    extraSnippets: Array.isArray(result.extra_snippets) ? result.extra_snippets : [],
    profile: result.profile
      ? {
          name: result.profile.name || null,
          url: result.profile.url || null,
          longName: result.profile.long_name || null,
          img: result.profile.img || null,
        }
      : null,
    source: 'brave:web'
  });

  if (candidates.length >= request.count) break;
}

const readCount = Math.min(request.readTopN, candidates.length);

if (candidates.length === 0 || readCount === 0) {
  return {
    json: {
      emptyResult: true,
      request: {
        ...request,
        candidateCount: candidates.length,
        readCount
      },
      candidateCount: candidates.length,
      readCount,
      record: null,
      readerUrl: null
    }
  };
}

return candidates.slice(0, readCount).map((record, index) => ({
  json: {
    request: {
      ...request,
      candidateCount: candidates.length,
      readCount
    },
    candidateCount: candidates.length,
    readCount,
    record: {
      ...record,
      readerRank: index + 1
    },
    readerUrl: `https://r.jina.ai/${record.url}`
  }
}));

const source = $('Loop Over Reader URLs').item.json;
const response = $input.item.json || {};

let content = '';
if (typeof response === 'string') {
  content = response;
} else if (typeof response.data === 'string') {
  content = response.data;
} else if (typeof response.body === 'string') {
  content = response.body;
} else {
  content = JSON.stringify(response);
}

const maxContentChars = source.request.maxContentChars || 6000;
const originalContentChars = content.length;
const truncatedContent = content.slice(0, maxContentChars);

return {
  json: {
    ...source,
    record: {
      ...source.record,
      reader: {
        status: 'ok',
        fetched: true,
        provider: 'jina_reader',
        readerUrl: source.readerUrl,
        contentType: 'markdown',
        contentChars: truncatedContent.length,
        originalContentChars,
        truncated: originalContentChars > maxContentChars,
        content: truncatedContent
      }
    },
    processedAt: new Date().toISOString()
  }
};

const source = $('Loop Over Reader URLs').item.json;
const input = $input.item.json || {};
const error = input.error || input;

return {
  json: {
    ...source,
    record: {
      ...source.record,
      reader: {
        status: 'error',
        fetched: false,
        provider: 'jina_reader',
        readerUrl: source.readerUrl,
        error: {
          message: error.message || input.message || 'Jina Reader request failed',
          name: error.name || input.name || null
        }
      }
    },
    processedAt: new Date().toISOString()
  }
};

const source = $input.item.json || {};

if (source.emptyResult) {
  return {
    json: {
      ...source,
      processedAt: new Date().toISOString()
    }
  };
}

return {
  json: {
    ...source,
    record: {
      ...source.record,
      reader: {
        status: 'skipped',
        fetched: false,
        provider: 'jina_reader',
        reason: 'readerUrl_missing_or_readTopN_zero'
      }
    },
    processedAt: new Date().toISOString()
  }
};

const items = $input.all().map((item) => item.json || {});
const first = items[0] || {};
const request = first.request || {};

const records = items
  .filter((item) => item.record && !item.emptyResult)
  .map((item) => item.record)
  .sort((a, b) => (a.rank || 0) - (b.rank || 0));

const readerStats = records.reduce((stats, record) => {
  const status = record.reader?.status || 'missing';
  stats[status] = (stats[status] || 0) + 1;
  return stats;
}, {});

return {
  json: {
    status: 'ok',
    provider: 'brave+jina_reader',
    query: request.query || null,
    candidateCount: request.candidateCount ?? first.candidateCount ?? records.length,
    recordCount: records.length,
    records,
    request,
    metadata: {
      braveCountRequested: request.count ?? null,
      readTopN: request.readTopN ?? null,
      readCount: request.readCount ?? records.length,
      readerDelaySeconds: request.readerDelaySeconds ?? null,
      maxContentChars: request.maxContentChars ?? null,
      readerStats,
      strategy: 'brave_overretrieve_then_jina_reader_top_n',
      reranker: 'not_enabled_yet'
    },
    receivedAt: new Date().toISOString()
  }
};

let request = {};
try {
  request = $('Normalize Input').first().json;
} catch (error) {
  request = $input.item.json || {};
}

const input = $input.item.json || {};
const error = input.error || input;

return {
  json: {
    status: 'error',
    provider: 'brave+jina_reader',
    query: request.query || input.query || null,
    candidateCount: 0,
    recordCount: 0,
    records: [],
    error: {
      message: error.message || input.message || 'Search workflow failed before producing results',
      name: error.name || input.name || null,
    },
    request,
    receivedAt: new Date().toISOString()
  }
};
